body {
  font-family: 'Inter', sans-serif;
  font-size: 16px;
  line-height: 1.6; /* Unitless value for better scaling relative to font-size */
}

h1 {
  font-size: 2.5em;
  line-height: 1.15; /* Tighter line-height for larger headings */
}

p {
  margin-bottom: 1em; /* Ensures consistent vertical spacing between paragraphs */
}

.small-text {
  font-size: 0.875em;
  line-height: 1.5; /* Slightly tighter for smaller text, adjusting for legibility */
}
